#include<bits/stdc++.h>
using namespace std;
#define ll long long
struct A{
	ll w,l;
	bool jl;
	friend bool operator<(A B,A C){
		if(B.jl<C.jl)return 1;
		if(B.w==C.w)return B.l<C.l;
		return B.w>C.w;
	}
}a[50005];
ll f[50005];
long double slope(ll p1,ll p2){//a[p1].l<a[p2].l
	ll x1=a[p1].l,y1=f[p1-1],
	   x2=a[p2].l,y2=f[p2-1];
	return (long double)1.0*(y2-y1)/(x2-x1);
}
ll n,sta[50005],p1=1,p2=1;
int main(){
	ios::sync_with_stdio(false);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i].w>>a[i].l;
	}
	sort(a+1,a+1+n);
	for(int i=2;i<=n;i++){
		if(a[i].l<=a[p1].l&&a[i].w<=a[p1].w)a[i].jl=1;
		else p1=i;
	}
	p1=1;
	sort(a+1,a+1+n);
	while(a[n].jl)n--;
    reverse(a+1,a+1+n);
	for(int i=1;i<=n;i++){
		while(p2>p1+1&&slope(sta[p2-1],sta[p2-2])<slope(i,sta[p2-1]))p2--;
		sta[p2++]=i;
		while(p1<p2-1&&(long double)-1.0*a[i].w<slope(sta[p1],sta[p1+1]))p1++;
		int j=sta[p1];
		f[i]=a[i].w*a[j].l+f[j-1];
	}
	cout<<f[n];
	return 0;
}
